script:
await page.locator('[aria-label] Delete').click();
const deleteButtonLocator = page.locator('[aria-label] Delete');
await expect(deleteButtonLocator).toBeVisible();
return { passed: true };

await page.fill('#todo-input', 'Test text');
await page.click('#add-btn');
await page.locator('#todo-input').waitFor();
await page.locator('#todo-input').locator('[placeholder]').update('Test text');
const error = await page.locator('#todo-input').locator('[placeholder]').getAttribute('placeholder');
return { passed: error === 'Test text' };

try {
  const allLink = page.locator('text=All');
  await allLink.click();
  await page.waitForLoadState('networkidle');
  const error = await page.evaluate(() => {
    const errors = [];
    for (const error of window.performance.getEntriesByName('domInteractive')) {
      if (error.name === 'TypeError' || error.name === 'SyntaxError') {
        errors.push(error.message);
      }
    }
    return errors;
  });
  if (error.length === 0) {
    return { passed: true };
  } else {
    return { passed: false, error: error.join('\n') };
  }
} catch (err) {
  return { passed: false, error: err.message };
}
